import Antimetal from '@antimetal/sdk';

const client = new Antimetal({
  apiKey: process.env['ANTIMETAL_API_KEY'], // This is the default and can be omitted
});

const issue = await client.issues.create({
  description: 'x',
  environment: 'x',
  title: 'x',
});

console.log(issue.uuid);

